import React, { useEffect, useRef } from 'react';

const CanvasBackground = () => {
  const canvasRef = useRef(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    const $ = canvas.getContext('2d');
    canvas.width = window.innerWidth;
    canvas.height = window.innerHeight;
    
    var col = function(x, y, r, g, b) {
      $.fillStyle = "rgb(" + (r-100) + "," + (g-100) + "," + (b-100) + ")";
      $.fillRect(x, y, 1,1);
    }
    
    var R = function(x, y, t) {
      return( Math.floor(128 + 64*Math.cos( (x*x-y*y)/300 + t )) );
    }
    
    var G = function(x, y, t) {
      return( Math.floor(128 + 64*Math.sin( (x*x*Math.cos(t/4)+y*y*Math.sin(t/3))/300 ) ) );
    }
    
    var B = function(x, y, t) {
      return( Math.floor(128 + 64*Math.sin( 5*Math.sin(t/9) + ((x-100)*(x-100)+(y-100)*(y-100))/1100) ));
    }
    
    var t = 0;
    
    var run = function() {
      for(var x=0;x<=35;x++) {
        for(var y=0;y<=35;y++) {
          col(x, y, R(x,y,t), G(x,y,t), B(x,y,t));
        }
      }
      t = t + 0.005;
      window.requestAnimationFrame(run);
    }
    
    run();
  }, []);

  return <canvas ref={canvasRef} style={{ position: 'absolute', top: 0, left: 0, zIndex: -1, width: '100%', height: '100%' }} />;
};

export default CanvasBackground;
